import { Component, ElementRef, ViewChild, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router, ActivatedRoute } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { AuthService } from '../../../core/services/auth.service';
import { SiteviewService } from '../../../core/services/siteview.service';
import { Marker, MarkerType } from '../../../core/models/siteview.models';

@Component({
  selector: 'app-siteplan',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './siteplan.component.html',
  styleUrl: './siteplan.component.css',
})
export class SiteplanComponent {
  @ViewChild('stage') stage?: ElementRef<HTMLElement>;

  private readonly projectId = this.route.parent?.snapshot.paramMap.get('id') ?? '';
  private readonly qp = toSignal(this.route.queryParamMap, { requireSync: true });
  private readonly refresh = signal(0);

  readonly plan = computed(() => this.sv.sitePlanForProject(this.projectId));
  readonly markers = computed<Marker[]>(() => {
    this.refresh();
    const p = this.plan();
    return p ? this.sv.markersForPlan(p.id) : [];
  });

  readonly selectedId = computed(() => this.qp().get('marker'));
  readonly modalOpen = computed(() => this.qp().get('modal') === 'marker');

  // live drag override so the marker follows the pointer smoothly
  private draggingId: string | null = null;
  readonly dragPos = signal<{ id: string; x: number; y: number } | null>(null);

  // pending new-marker placement
  pending = { x: 0.5, y: 0.5 };
  draft = { type: 'equipment' as MarkerType, note: '' };

  constructor(
    public auth: AuthService,
    private sv: SiteviewService,
    private router: Router,
    private route: ActivatedRoute,
  ) {}

  markerLeft(m: Marker): number {
    const d = this.dragPos();
    return (d && d.id === m.id ? d.x : m.x) * 100;
  }
  markerTop(m: Marker): number {
    const d = this.dragPos();
    return (d && d.id === m.id ? d.y : m.y) * 100;
  }

  private normFromEvent(ev: PointerEvent): { x: number; y: number } {
    const rect = this.stage!.nativeElement.getBoundingClientRect();
    return {
      x: Math.min(1, Math.max(0, (ev.clientX - rect.left) / rect.width)),
      y: Math.min(1, Math.max(0, (ev.clientY - rect.top) / rect.height)),
    };
  }

  selectMarker(id: string, ev: Event): void {
    ev.stopPropagation();
    this.router.navigate([], { queryParams: { marker: id }, queryParamsHandling: 'merge' });
  }

  // ---- Drag (planner only) ----
  onMarkerPointerDown(m: Marker, ev: PointerEvent): void {
    if (!this.auth.isPlanner()) return;
    ev.preventDefault();
    ev.stopPropagation();
    this.draggingId = m.id;
    this.dragPos.set({ id: m.id, x: m.x, y: m.y });
    (ev.target as HTMLElement).setPointerCapture(ev.pointerId);
  }
  onMarkerPointerMove(ev: PointerEvent): void {
    if (!this.draggingId) return;
    const { x, y } = this.normFromEvent(ev);
    this.dragPos.set({ id: this.draggingId, x, y });
  }
  onMarkerPointerUp(m: Marker, ev: PointerEvent): void {
    if (this.draggingId !== m.id) return;
    const { x, y } = this.normFromEvent(ev);
    this.sv.moveMarker(m.id, x, y); // PATCH /markers/:id
    this.draggingId = null;
    this.dragPos.set(null);
    this.refresh.update((n) => n + 1);
  }

  // ---- Add marker (planner) ----
  onStageClick(ev: MouseEvent): void {
    if (!this.auth.isPlanner() || !this.plan()) return;
    const rect = this.stage!.nativeElement.getBoundingClientRect();
    this.pending = {
      x: Math.min(1, Math.max(0, (ev.clientX - rect.left) / rect.width)),
      y: Math.min(1, Math.max(0, (ev.clientY - rect.top) / rect.height)),
    };
    this.draft = { type: 'equipment', note: '' };
    this.router.navigate([], { queryParams: { modal: 'marker' }, queryParamsHandling: 'merge' });
  }

  closeModal(): void {
    this.router.navigate([], { queryParams: { modal: null }, queryParamsHandling: 'merge' });
  }

  saveMarker(): void {
    const p = this.plan();
    if (!p || !this.draft.note.trim()) return;
    const created = this.sv.createMarker({
      planId: p.id,
      x: this.pending.x,
      y: this.pending.y,
      type: this.draft.type,
      note: this.draft.note.trim(),
    });
    this.refresh.update((n) => n + 1);
    this.router.navigate([], { queryParams: { modal: null, marker: created.id }, queryParamsHandling: 'merge' });
  }

  selectedMarker = computed(() => this.markers().find((m) => m.id === this.selectedId()) ?? null);
}
